def strip_hidden(soup: BeautifulSoup) -> int:
    """移除所有 style 含 display:none 的元素（连子树一起删）。返回删除条数。"""
    targets = []
    for el in soup.find_all(True):
        if not isinstance(el, Tag):
            continue
        st = el.get("style") or ""
        if re.search(r"display\s*:\s*none\b", st, re.IGNORECASE):
            targets.append(el)
    # 反向 decompose，避免父级先 decompose 后子级访问失败
    for el in reversed(targets):
        try:
            el.decompose()
        except Exception:
            pass
    return len(targets)

