def iter_runs_from_p(p_tag: Tag, parent_p_style: dict):
    """把一个 <p> 解析成 [(text, span_style_dict), ...]，<br> 用特殊标记 ('\n', None) 表示段落分隔。"""
    out = []
    for child in p_tag.children:
        if isinstance(child, NavigableString):
            t = str(child)
            if t.strip() == "":
                continue
            out.append((t, parent_p_style))
        elif isinstance(child, Tag):
            if child.name == "br":
                out.append(("__BR__", None))
            elif child.name == "span":
                span_style = parse_style(child.get("style"))
                merged = {**parent_p_style, **span_style}
                inner_text = child.get_text(strip=False)
                if inner_text.strip() == "":
                    continue
                out.append((inner_text, merged))
            else:
                # 其他内联标签（很少见），按文本处理
                t = child.get_text(strip=False)
                if t.strip():
                    out.append((t, parent_p_style))
    return out


