BLOCK_TAGS = {"div", "p", "table", "section", "article", "header", "footer", "ul", "ol", "li"}


def _walk_content(node, inherited_style: dict, runs_buf: list, paras_out: list):
    """递归遍历 .shp 内所有节点，把 inline 文字累积到 runs_buf，遇到 block 边界时刷成一段。
    跳过嵌套 .shp 和 table（外层另行处理）。"""
    if isinstance(node, NavigableString):
        text = str(node)
        # 保留段内空格但跳过纯空白节点
        if text.strip():
            runs_buf.append((text, inherited_style))
        return

    if not isinstance(node, Tag):
        return

    cls = node.get("class") or []
    if "shp" in cls:
        return
    if node.name == "table":
        return
    if node.name == "br":
        runs_buf.append(("__BR__", None))
        return
    if node.name == "img":
        return  # 图片由外层 add_picture 处理

    if node.name == "span":
        merged = {**inherited_style, **parse_style(node.get("style"))}
        for ch in node.children:
            _walk_content(ch, merged, runs_buf, paras_out)
        return

    if node.name == "p" and "pp" in cls:
        if runs_buf:
            paras_out.append({"alignment": "left", "runs": list(runs_buf)})
            runs_buf.clear()
        p_style_self = parse_style(node.get("style"))
        merged = {**inherited_style, **p_style_self}
        inner_runs: list = []
        for ch in node.children:
            _walk_content(ch, merged, inner_runs, paras_out)
        align = (p_style_self.get("text-align") or "left").lower()
        paras_out.append({"alignment": align, "runs": inner_runs})
        return

    if node.name in BLOCK_TAGS:
        merged = {**inherited_style, **parse_style(node.get("style"))}
        # 判断该容器是否包含 block 子级
        has_block_child = False
        for ch in node.children:
            if isinstance(ch, Tag):
                if ch.name in BLOCK_TAGS or "shp" in (ch.get("class") or []):
                    has_block_child = True
                    break
        if has_block_child:
            if runs_buf:
                paras_out.append({"alignment": "left", "runs": list(runs_buf)})
                runs_buf.clear()
            for ch in node.children:
                _walk_content(ch, merged, runs_buf, paras_out)
            if runs_buf:
                paras_out.append({"alignment": "left", "runs": list(runs_buf)})
                runs_buf.clear()
        else:
            # inline-only 容器（典型的 flex 行：div > span span span）
            inner_runs: list = []
            for ch in node.children:
                _walk_content(ch, merged, inner_runs, paras_out)
            if inner_runs:
                d_style = parse_style(node.get("style"))
                align = (d_style.get("text-align") or "left").lower()
                paras_out.append({"alignment": align, "runs": inner_runs})
        return

    # 其他 inline 标签（i / b / strong / em ...）：当 inline 处理
    merged = {**inherited_style, **parse_style(node.get("style"))}
    for ch in node.children:
        _walk_content(ch, merged, runs_buf, paras_out)


