def parse_padding(s: str | None):
    """解析 padding shorthand，返回 (top, right, bottom, left)。仅支持 px 单位。"""
    if not s:
        return (0.0, 0.0, 0.0, 0.0)
    parts = re.findall(r"(-?\d+(?:\.\d+)?)\s*(?:px)?\b", s)
    if not parts:
        return (0.0, 0.0, 0.0, 0.0)
    vals = [float(p) for p in parts]
    if len(vals) == 1:
        return (vals[0], vals[0], vals[0], vals[0])
    if len(vals) == 2:
        return (vals[0], vals[1], vals[0], vals[1])
    if len(vals) == 3:
        return (vals[0], vals[1], vals[2], vals[1])
    return (vals[0], vals[1], vals[2], vals[3])


def parse_flex_grow(s: str | None) -> float:
    """解析 flex / flex-grow shorthand。'flex:1' → 1.0；'flex:1.4' → 1.4。"""
    if not s:
        return 0.0
    m = re.match(r"\s*(-?\d+(?:\.\d+)?)", s)
    return float(m.group(1)) if m else 0.0


