def _resolve_v_anchor(style: dict, has_direct_p: bool) -> int:
    jc = (style.get("justify-content") or "").lower()
    align_items = (style.get("align-items") or "").lower()
    flex_dir = (style.get("flex-direction") or "row").lower()
    v_anchor = VANCHOR_MAP.get(jc, MSO_ANCHOR.TOP)
    if flex_dir.startswith("row"):
        if align_items == "center":
            v_anchor = MSO_ANCHOR.MIDDLE
        elif align_items == "flex-end":
            v_anchor = MSO_ANCHOR.BOTTOM
        elif align_items == "flex-start":
            v_anchor = MSO_ANCHOR.TOP
    if jc in ("space-between", "space-around", "space-evenly"):
        v_anchor = MSO_ANCHOR.MIDDLE
    if not has_direct_p and jc not in ("flex-start",) and flex_dir.startswith("column"):
        v_anchor = MSO_ANCHOR.MIDDLE
    return v_anchor


