def estimate_content_height(node: Tag) -> float:
    """粗略估算 box 内容所需高度（px）。基于段落数 × 字号 × 行高 + padding。"""
    paras = collect_blocks(node)
    text_h = 0.0
    for p in paras:
        runs = p.get("runs") or []
        if not runs:
            text_h += 14 * 1.3 * 1.33
            continue
        # 段内最大字号
        max_sz = 0.0
        line_count = 1
        for text, st in runs:
            if text == "__BR__":
                line_count += 1
                continue
            sz = pt_value(st.get("font-size") if st else None) or 14
            if sz > max_sz:
                max_sz = sz
        if max_sz == 0:
            max_sz = 14
        # pt → px ≈ 1.33；行高 ≈ 1.3
        text_h += max_sz * 1.3 * 1.33 * line_count
    s = parse_style(node.get("style"))
    pad = parse_padding(s.get("padding"))
    return text_h + pad[0] + pad[2] + 4

